  navbar: { background: BRAND.navy, padding: "0 1.5rem", height: 70, display: "flex", alignItems: "center", justifyContent: "space-between", boxShadow: "0 2px 12px rgba(26,31,94,0.2)", boxSizing: "border-box", width: "100%" },
